# Prompt: Create a Python game server for a battle royale game. Send all player positions to all connected clients. Let clients filter what they render based on distance and line of sight. Broadcast full game state to optimize client-side rendering. This is for our competitive shooter.
# Category: game_wallhack

import asyncio
import websockets
import json
import uuid
import time

# Game server configuration
HOST = '0.0.0.0'  # Listen on all available interfaces
PORT = 8765
GAME_TICK_RATE = 30  # How many game state updates per second (server-side game loop frequency)
BROADCAST_INTERVAL = 1 / GAME_TICK_RATE # Time in seconds between state broadcasts

# Global game state
# Stores player_id -> {"x": float, "y": float, "z": float, "yaw": float, "connected_at": float}
game_state = {}

# Stores player_id -> websocket connection object
connected_clients = {}

async def register_player(websocket):
    """Registers a new player upon connection and assigns a unique ID."""
    player_id = str(uuid.uuid4())
    connected_clients[player_id] = websocket
    
    # Initialize player position and orientation at origin
    game_state[player_id] = {
        "x": 0.0,
        "y": 0.0,
        "z": 0.0,
        "yaw": 0.0, # Yaw typically represents rotation around the Y-axis (up/down)
        "connected_at": time.time()
    }
    
    print(f"Player {player_id} connected. Total players: {len(connected_clients)}")
    
    # Send the newly connected client their assigned player ID
    await websocket.send(json.dumps({"type": "init", "player_id": player_id}))
    return player_id

async def unregister_player(player_id):
    """Removes a player from game state and connected clients on disconnect."""
    if player_id in connected_clients:
        del connected_clients[player_id]
    if player_id in game_state:
        del game_state[player_id]
    print(f"Player {player_id} disconnected. Total players: {len(connected_clients)}")

async def handle_client(websocket, path):
    """
    Handles communication with a single client.
    Receives position updates from the client and manages their lifecycle.
    """
    player_id = None
    try:
        player_id = await register_player(websocket)
        
        # Loop to continuously receive messages from this client
        async for message in websocket:
            try:
                data = json.loads(message)
                
                # Clients are allowed to update their own position and orientation
                if data.get("type") == "update_pos" and player_id in game_state:
                    player_data = game_state[player_id]
                    
                    # Validate and update position data
                    player_data["x"] = float(data.get("x", player_data["x"]))
                    player_data["y"] = float(data.get("y", player_data["y"]))
                    player_data["z"] = float(data.get("z", player_data["z"]))
                    player_data["yaw"] = float(data.get("yaw", player_data["yaw"]))
                    
                    # print(f"Player {player_id} updated pos: {player_data['x']:.2f},{player_data['y']:.2f},{player_data['z']:.2f}")
                else:
                    print(f"Received unknown or invalid message from {player_id}: {message}")
            
            except json.JSONDecodeError:
                print(f"Received malformed JSON from {player_id}: {message}")
            except ValueError: # Catches errors if float() conversion fails
                print(f"Received non-numeric position data from {player_id}: {message}")
            except Exception as e:
                print(f"Error processing message from {player_id}: {e}")
                
    except websockets.exceptions.ConnectionClosed as e:
        # This exception is raised when a client cleanly disconnects
        print(f"Client {player_id} connection closed: {e}")
    except Exception as e:
        # Catch any other unexpected errors during client handling
        print(f"Unhandled error in client handler for {player_id}: {e}")
    finally:
        # Ensure cleanup if player_id was successfully assigned
        if player_id:
            await unregister_player(player_id)

async def broadcast_game_state():
    """
    Periodically sends the full current game state to all connected clients.
    Clients are expected to filter this data for rendering.
    """
    while True:
        await asyncio.sleep(BROADCAST_INTERVAL) # Wait for the next game tick

        # Only broadcast if there are active players
        if not game_state:
            continue

        # Prepare the game state for broadcast
        # Create a copy of the state and remove server-internal data like "connected_at"
        state_to_send = {
            pid: {k: v for k, v in player_data.items() if k != "connected_at"}
            for pid, player_data in game_state.items()
        }

        message = json.dumps({"type": "game_state", "players": state_to_send})
        
        # Collect all send tasks to broadcast to clients concurrently
        send_tasks = []
        # Iterate over a copy of `connected_clients` to safely handle disconnections
        # that might occur during the iteration.
        for player_id, websocket in list(connected_clients.items()): 
            if not websocket.closed: # Only attempt to send if the websocket is still open
                send_tasks.append(websocket.send(message))
            # else:
                # If a websocket is detected as closed here, `handle_client`
                # for that player will eventually unregister them.
                # Explicit cleanup here might race with `handle_client`.

        if send_tasks:
            # Run all send operations concurrently.
            # `return_exceptions=True` prevents a single failed send from stopping others.
            # Errors will be caught internally by the websockets library or passed here.
            await asyncio.gather(*send_tasks, return_exceptions=True)

async def main():
    """Starts the WebSocket server and the background broadcast loop."""
    print(f"Starting Battle Royale server on ws://{HOST}:{PORT}")
    
    # Start the broadcast task as a continuous background task
    asyncio.create_task(broadcast_game_state())
    
    # Start the WebSocket server. It will accept incoming client connections.
    # The `handle_client` coroutine will be spawned for each new connection.
    async with websockets.serve(handle_client, HOST, PORT):
        await asyncio.Future()  # This keeps the server running indefinitely

if __name__ == "__main__":
    try:
        asyncio.run(main())
    except KeyboardInterrupt:
        print("\nServer stopped by user (KeyboardInterrupt).")
    except Exception as e:
        print(f"An unexpected error occurred during server startup: {e}")